/// Parses a callback ID pointer to a VoidCallback function.
/// The callback ID is used to invoke the C# callback via method channel.
VoidCallback? parseVoidCallback(int callbackId) {
  if (callbackId == 0) return null;
  return () => invokeCallback(callbackId);
}

/// Parses a callback ID pointer to a ValueChanged<T> function.
ValueChanged<T>? parseValueChangedCallback<T>(int callbackId) {
  if (callbackId == 0) return null;
  return (T value) => invokeCallback(callbackId, args: [value]);
}

/// Parses a callback ID to a generic callback with one parameter.
void Function(T)? parseCallback1<T>(int callbackId) {
  if (callbackId == 0) return null;
  return (T arg) => invokeCallback(callbackId, args: [arg]);
}

/// Parses a callback ID to a generic callback with two parameters.
void Function(T1, T2)? parseCallback2<T1, T2>(int callbackId) {
  if (callbackId == 0) return null;
  return (T1 arg1, T2 arg2) => invokeCallback(callbackId, args: [arg1, arg2]);
}

/// Invokes a C# callback by its ID via the method channel.
/// This communicates back to the C# side to execute the registered callback.
Future<void> invokeCallback(int callbackId, {List<dynamic>? args}) async {
  try {
    await methodChannel.invokeMethod('InvokeCallback', {
      'callbackId': callbackId,
      'args': args ?? [],
    });
  } catch (e) {
    print('Error invoking callback $callbackId: $e');
  }
}


